// VULNERABLE: User input is inserted directly into the SQL string
const email = req.body.email; // attacker sends: ' OR 1=1 --

// This becomes: SELECT * FROM users WHERE email = '' OR 1=1 --'
// Which returns ALL users in the database
const result = await pool.query(
  `SELECT * FROM users WHERE email = '${email}'`
);

// Even worse with DELETE:
const id = req.params.id; // attacker sends: 1; DROP TABLE users; --
await pool.query(`DELETE FROM posts WHERE id = ${id}`);
// This deletes the entire users table

// SAFE: Parameterized query -- the database treats $1 as data, not code
const result = await pool.query(
  'SELECT * FROM users WHERE email = $1',
  [req.body.email]
);

// SAFE: Prisma (all queries are parameterized automatically)
const user = await prisma.user.findUnique({
  where: { email: req.body.email },
});

// SAFE: Drizzle (parameterized by design)
const user = await db.select()
  .from(users)
  .where(eq(users.email, req.body.email));

// Rule: NEVER concatenate user input into SQL strings.
// Every ORM and query builder handles this for you.
